def count_hot_sensors(spec: dict) -> int {
    h = Hub();
    for d in list(spec["devices"]) {
        if d["kind"] == "sensor" { h ++> Sensor(reading=int(d["reading"])); }
        else { h ++> Camera(fps=int(d["fps"])); }
    }
    return (h spawn HotScan(low=int(spec["min"]))).count;
}

