def top_city_revenue(spec: dict) -> str:
    """Name of the city whose shops earn the most in total; ties go to the alphabetically first city."""
    cities = spec["cities"]
    if not cities:
        return ""
    best = ""; bt = 0; seen = False
    for nm in sorted(cities):
        t = sum(cities[nm])
        if not seen or t > bt:
            best = nm; bt = t; seen = True
    return best

