def richest_department(spec: dict) -> str:
    """Department with the highest total salary; ties go to the alphabetically first name."""
    depts = spec["depts"]
    if not depts:
        return ""
    totals = {d: sum(sals) for d, sals in depts.items()}
    best = ""; bt = 0; seen = False
    for d in sorted(totals):
        if not seen or totals[d] > bt:
            best = d; bt = totals[d]; seen = True
    return best

